import{_ as o,o as e,c as p,a as r}from"./chunks/plugin-vue_export-helper.B0FdOn3A.js";const m=JSON.parse('{"title":"Проект с нуля","description":"","frontmatter":{"title":"Проект с нуля","date":"2021-11-24T00:00:00.000Z"},"headers":[],"relativePath":"posts/2021-11-24-poject-from-scratch.md","filePath":"posts/2021-11-24-poject-from-scratch.md"}'),a={name:"posts/2021-11-24-poject-from-scratch.md"};function c(s,t,i,l,_,n){return e(),p("div",null,[...t[0]||(t[0]=[r("<p>Многих разработчиков привлекает фраза &quot;проект с нуля&quot;. Это как искать девственницу - мало кто ответит на вопрос &quot;что ты будешь с ней делать?&quot; Гораздо проще улучшать существующий проект, чем создавать с нуля свой. Проект с нуля это огромный объем работ, который нужно сделать чтобы запуститься.</p><p>Для PM это GAP-анализ (чего нет чтобы было), стратегическое планирование, создание плана коммуникаций и выбор методологии управления. Для аналитика это подготовка и детализация сотни страниц в базе знаний, описывающих функционал гораздо детальнее, чем в ТЗ. Для разработчиков это выбор технологий с учетом ситуации на рынке труда, собственных компетенций и требований (функциональных и нефункциональных).</p><p>Это как спроектировать дом в чистом поле. Нужно учесть всё: ландшафт, климат, доступность стройматериалов и рабочих, площадь участка и обязательно - пожелания заказчика. Учесть нужно также внезапно возникающие требования в середине строительства. Например, заказчик может захотеть камин, хотя летом он от камина отказывался.</p><p>При планировании работ надо помнить о праздниках, отпусках и больничных, особенностях работы с квалифицированными и не очень людьми.</p><p>В моей практике было только два проекта с нуля. И вот мои усвоенные уроки:</p><ol><li>Прежде чем браться за проект, нужно понимать какой объем работ действительно осуществим в текущих условиях. Это должны быть конкретные рамки (scope of work). Остальное можно оставить на потом если хватит средств. Часто выбор очевиден - ради ускорения сайта с 10 до 1 секунды можно переписывать софт пару лет, чтобы получить современный SPA, или пригласить эксперта чтобы он настроил Webpack за день.</li><li>Верхнеуровневую оценку после подписания договора можно сразу выбрасывать и начинать делать детальный план работ от простого к сложному. Половину этого плана тоже придётся выбросить после первой демонстрации успехов. Требования меняются. Коммуникации важнее начального ТЗ. Основная ценность проектирования и разработки в том, что мы, делая итеративные поставки, даём заказчику понимание, что он в итоге хочет.</li><li>Хорошая практика - в середине проекта объявить о том, что вы готовы поработать ещё пару месяцев за те же деньги (при условии, что это было учтено в изначальной оценке)</li><li>Очень важно (!!!) сразу создать план коммуникации со всеми заинтересованными лицами (регулярность обсуждений план-факта, структурность общения, своевременную и качественную обработку предложений). Иначе бывает сложно обеспечить доступность выгодоприобретателей. На каждой встрече должен быть человек, который будет слушать внимательнее всех и не вмешиваться.</li><li>Отлично если удастся убедить заказчика провести мини-исследование осуществимости задуманного. Двухнедельный discovery-проект поможет составить чёткое видение будущего продукта и показать возможности и риски ещё до подписания договора.</li></ol>",6)])])}const f=o(a,[["render",c]]);export{m as __pageData,f as default};
